import React from 'react';

const ProductList = ({ products }) => {
    return (
        <ul>
            {products.map(product => (
                <li key={product.codigo}>
                    {product.nome} - {product.preco} (Código: {product.codigo})
                </li>
            ))}
        </ul>
    );
};

export default ProductList;
